// frontend/src/event/EventDetail.js
import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';

const EventDetail = () => {
  const { id } = useParams(); // URLからイbytes:\xe3\x83bytes:\x99ントIDを取得
  const [event, setEvent] = useState(null);

  useEffect(() => {
    //bytes: \xe3\x82bytes:\xa4bytes:\xe3\x83bytes:\x99ントIDに基bytes:\xe3\x81bytes:\xa5いてイbytes:\xe3\x83bytes:\x99ントのbytes:\xe8\xa9bytes:\xb3bytes:\xe7\xb4bytes:\xb0情報を取得するロジックをここにbytes:\xe5\xaebytes:\x9f装
    const fetchEventDetail = async () => {
      const response = await fetch(`http://localhost:8000/event/get?event_id=${id}`);
      const data = await response.json();
      setEvent(data[0]); //bytes: \xe3\x82bytes:\xa4bytes:\xe3\x83bytes:\x99ントのbytes:\xe8\xa9bytes:\xb3bytes:\xe7\xb4bytes:\xb0情報をbytes:\xe8\xa8bytes:\xad定
    };

    fetchEventDetail();
  }, [id]);

  if (!event) {
    return <div>Loading...</div>;
  }

  return (
    <div>
      <h1>{event.event_name}</h1>
      <p>{event.event_info}</p>
      // その他のイbytes:\xe3\x83bytes:\x99ントbytes:\xe8\xa9bytes:\xb3bytes:\xe7\xb4bytes:\xb0情報を表示
    </div>
  );
};

export default EventDetail;
